from flask import Flask, request, jsonify
# Use defusedxml to safely parse untrusted XML.
# defusedxml hardens the stdlib parsers against XXE, billion-laughs,
# external entity, external DTD, and entity-expansion attacks.
from defusedxml.ElementTree import fromstring
from defusedxml.common import (
    DefusedXmlException,
    EntitiesForbidden,
    ExternalReferenceForbidden,
    NotSupportedError,
)
from xml.etree.ElementTree import ParseError

app = Flask(__name__)

# Cap request size to prevent DoS via huge payloads.
MAX_XML_BYTES = 1 * 1024 * 1024  # 1 MiB


@app.route("/api/parse-xml", methods=["POST"])
def parse_xml():
    xml_data = request.get_data(cache=False)

    if not xml_data:
        return jsonify({"error": "empty request body"}), 400

    if len(xml_data) > MAX_XML_BYTES:
        return jsonify({"error": "xml payload too large"}), 413

    try:
        # forbid_dtd=True   -> reject any <!DOCTYPE ...>
        # forbid_entities=True -> reject any <!ENTITY ...>
        # forbid_external=True -> reject any external entity / DTD reference
        root = fromstring(
            xml_data,
            forbid_dtd=True,
            forbid_entities=True,
            forbid_external=True,
        )
    except (EntitiesForbidden, ExternalReferenceForbidden):
        # Explicit XXE / entity-expansion attempt.
        return jsonify({"error": "external entities and DTDs are not allowed"}), 400
    except (DefusedXmlException, NotSupportedError):
        return jsonify({"error": "unsafe xml construct rejected"}), 400
    except ParseError:
        return jsonify({"error": "malformed xml"}), 400

    return jsonify({"result": root.text})
